INSERT INTO ports (name, unlocode, country, latitude, longitude, has_freezing_risk, freezing_notes, website, notes) SELECT 'Gdańsk', 'PLGDN', 'Poland', 54.416667, 18.65, 0, 'Official port information states lack of ice and no tides, with year-round operation. Always verify current ice reports for winter calls.', 'https://www.portgdansk.pl/en/', 'Port divided into Inner Port and Outer Port. Coordinates from Port of Gdańsk: 54°25′N, 18°39′E. Inner Port max draft 10.6 m; Outer Port max draft 15.0 m. UN/LOCODE PLGDN verified against UNECE.' WHERE NOT EXISTS (SELECT 1 FROM ports WHERE name='Gdańsk');
INSERT INTO ports (name, unlocode, country, latitude, longitude, has_freezing_risk, freezing_notes, website, notes) SELECT 'Szczecin', 'PLSZZ', 'Poland', 53.418889, 14.57, 1, 'Seasonal winter-navigation restrictions can be imposed for vessels bound to Szczecin/Świnoujście when Maritime Administration ice reports are published.', 'https://www.port.szczecin.pl/en/', 'Port is about 68 km from the sea; official port information states max draft up to 9.15 m and LOA up to 215 m. DB Port Szczecin coordinates: 53°25′08″N, 14°34′12″E. UN/LOCODE PLSZZ verified against UNECE.' WHERE NOT EXISTS (SELECT 1 FROM ports WHERE name='Szczecin');
INSERT INTO ports (name, unlocode, country, latitude, longitude, has_freezing_risk, freezing_notes, website, notes) SELECT 'Świnoujście', 'PLSWI', 'Poland', 53.9, 14.25, 0, 'Port/operator information describes Świnoujście as ice-free/no tides; winter restrictions for vessels bound to Świnoujście/Szczecin may still be imposed by the Maritime Administration when ice reports are active.', 'https://www.port.szczecin.pl/en/', 'Official port information states max draft up to 13.5 m and LOA up to 270 m. UNECE UN/LOCODE coordinates: 5354N 01415E; UN/LOCODE PLSWI verified against UNECE.' WHERE NOT EXISTS (SELECT 1 FROM ports WHERE name='Świnoujście');
