INSERT INTO approach_channels (port_id, name, depth_m, width_m, max_loa_m, max_beam_m, max_draft_m, max_air_draft_m, pilot_required, tug_required, notes) SELECT (SELECT id FROM ports WHERE name='Gdańsk'), 'Gdańsk Outer Port / deepwater fairway', 17.0, NULL, 400, NULL, 15.0, NULL, 1, 0, 'Official Gdańsk info: 17 m deepwater fairway, max draft up to 15 m, no tides/lack of ice; about-port page states outer port can admit vessels up to 400 m. Baltic Hub terminal-specific max LOA is 425 m.' WHERE NOT EXISTS (SELECT 1 FROM approach_channels WHERE port_id=(SELECT id FROM ports WHERE name='Gdańsk') AND name='Gdańsk Outer Port / deepwater fairway');
INSERT INTO approach_channels (port_id, name, depth_m, width_m, max_loa_m, max_beam_m, max_draft_m, max_air_draft_m, pilot_required, tug_required, notes) SELECT (SELECT id FROM ports WHERE name='Gdańsk'), 'Gdańsk Inner Port', NULL, NULL, NULL, NULL, 10.6, NULL, 1, 0, 'Inner Port maximum draft 10.6 m according to official Port of Gdańsk general information.' WHERE NOT EXISTS (SELECT 1 FROM approach_channels WHERE port_id=(SELECT id FROM ports WHERE name='Gdańsk') AND name='Gdańsk Inner Port');
INSERT INTO approach_channels (port_id, name, depth_m, width_m, max_loa_m, max_beam_m, max_draft_m, max_air_draft_m, pilot_required, tug_required, notes) SELECT (SELECT id FROM ports WHERE name='Świnoujście'), 'Świnoujście approach / port limits', NULL, NULL, 270, NULL, 13.5, NULL, 1, 0, 'Official port information: Świnoujście can handle vessels of draft up to 13.5 m and length up to 270 m.' WHERE NOT EXISTS (SELECT 1 FROM approach_channels WHERE port_id=(SELECT id FROM ports WHERE name='Świnoujście') AND name='Świnoujście approach / port limits');
INSERT INTO approach_channels (port_id, name, depth_m, width_m, max_loa_m, max_beam_m, max_draft_m, max_air_draft_m, pilot_required, tug_required, notes) SELECT (SELECT id FROM ports WHERE name='Świnoujście'), 'Świnoujście Offshore Terminal approach track', 12.5, 140, 182, 60, 11.0, NULL, 1, 0, 'New approach track to offshore terminal: 12.5 m deep, 140 m wide; designed for jack-up vessels LOA 182 m, beam 60 m, max draft 11.0 m.' WHERE NOT EXISTS (SELECT 1 FROM approach_channels WHERE port_id=(SELECT id FROM ports WHERE name='Świnoujście') AND name='Świnoujście Offshore Terminal approach track');
INSERT INTO approach_channels (port_id, name, depth_m, width_m, max_loa_m, max_beam_m, max_draft_m, max_air_draft_m, pilot_required, tug_required, notes) SELECT (SELECT id FROM ports WHERE name='Szczecin'), 'Świnoujście-Szczecin fairway to Szczecin', NULL, 90, 215, NULL, 9.15, NULL, 1, 0, 'Guidance: main fairway from central breakwater to Szczecin about 67.4 km, technical width 90 m from 5.5 km to 67.4 km. Official basic port info: Szczecin max draft up to 9.15 m and LOA up to 215 m.' WHERE NOT EXISTS (SELECT 1 FROM approach_channels WHERE port_id=(SELECT id FROM ports WHERE name='Szczecin') AND name='Świnoujście-Szczecin fairway to Szczecin');
INSERT INTO port_conditions (port_id, condition_type, start_month, end_month, severity, description) SELECT (SELECT id FROM ports WHERE name='Gdańsk'), 'ice/tide', NULL, NULL, 'low', 'Official port page states lack of tides/ice supports year-round operations. Keep current navigational notices checked for winter voyages.' WHERE NOT EXISTS (SELECT 1 FROM port_conditions WHERE port_id=(SELECT id FROM ports WHERE name='Gdańsk') AND condition_type='ice/tide' AND COALESCE(start_month,-1)=COALESCE(NULL,-1));
INSERT INTO port_conditions (port_id, condition_type, start_month, end_month, severity, description) SELECT (SELECT id FROM ports WHERE name='Szczecin'), 'winter navigation / ice restrictions', 12, 2, 'moderate', 'Maritime Administration winter navigation rules can impose ice-class/main-engine-power restrictions for vessels bound to Szczecin and Świnoujście from 1 Dec and additional requirements from 15 Jan when Ice Report is published.' WHERE NOT EXISTS (SELECT 1 FROM port_conditions WHERE port_id=(SELECT id FROM ports WHERE name='Szczecin') AND condition_type='winter navigation / ice restrictions' AND COALESCE(start_month,-1)=COALESCE(12,-1));
INSERT INTO port_conditions (port_id, condition_type, start_month, end_month, severity, description) SELECT (SELECT id FROM ports WHERE name='Świnoujście'), 'ice/tide', NULL, NULL, 'low', 'Port/operator sources describe Świnoujście as ice-free/no tides; however Maritime Administration winter navigation restrictions may still apply when Ice Report is active.' WHERE NOT EXISTS (SELECT 1 FROM port_conditions WHERE port_id=(SELECT id FROM ports WHERE name='Świnoujście') AND condition_type='ice/tide' AND COALESCE(start_month,-1)=COALESCE(NULL,-1));
INSERT INTO port_conditions (port_id, condition_type, start_month, end_month, severity, description) SELECT (SELECT id FROM ports WHERE name='Świnoujście'), 'winter navigation / ice restrictions', 12, 2, 'low-to-moderate', 'Restrictions may apply to vessels bound to Świnoujście/Szczecin depending on current Ice Report; verify with VTS Świnoujście.' WHERE NOT EXISTS (SELECT 1 FROM port_conditions WHERE port_id=(SELECT id FROM ports WHERE name='Świnoujście') AND condition_type='winter navigation / ice restrictions' AND COALESCE(start_month,-1)=COALESCE(12,-1));
